const (
	// BackgroundValue marks a pixel that fits the background model.
	BackgroundValue uint8 = 0
	// ForegroundValue marks a pixel that deviates from the background model.
	ForegroundValue uint8 = 255
	// ShadowValue marks a pixel that looks like the moving shadow of a
	// background object. It is only emitted when a model's DetectShadows option
	// is enabled.
	ShadowValue uint8 = 127
)

types.signature:
type BackgroundSubtractor interface {
	// Apply classifies frame against the current background model, updates the
	// model with the observation, and returns a fresh single-channel foreground
	// mask the same size as frame. Mask samples are [BackgroundValue],
	// [ForegroundValue] or [ShadowValue]. Every frame after the first must have
	// the same dimensions as the first; Apply panics on a size or shape it
	// cannot handle.
	Apply(frame *cv.Mat) (fgMask *cv.Mat)

	// GetBackgroundImage returns the model's current estimate of the static
	// background as a fresh single-channel [cv.Mat]. It returns nil before the
	// first call to Apply, when no model has been formed yet.
	GetBackgroundImage() *cv.Mat
}

type BackgroundSubtractorCNT struct {
	// ShadowParams supplies the embedded DetectShadows / ShadowValue /
	// ShadowThreshold configuration and their setters.
	ShadowParams

	// MinPixelStability is the number of consecutive stable frames after which a
	// pixel value is accepted as background.
	MinPixelStability int
	// MaxPixelStability caps the stability counter so an established background
	// can still be superseded within a bounded number of frames.
	MaxPixelStability int
	// UseHistory enables remembering the last trusted background value for
	// instant re-recognition.
	UseHistory bool
	// Tolerance is the absolute intensity difference within which two successive
	// observations count as "the same value".
	Tolerance float64
	// OpenKernel, when greater than 1, morphologically opens the mask at that odd
	// size before Apply returns it (see [CleanupMask]).
	OpenKernel int
	// contains filtered or unexported fields
}

type BackgroundSubtractorGMG struct {
	// NumInitFrames is the length of the initial learning period during which
	// Apply returns an all-background mask.
	NumInitFrames int
	// NumBins is the number of intensity quantisation bins per pixel.
	NumBins int
	// DecisionThreshold is the foreground-probability (1 - posterior background
	// probability) above which a pixel is classified as foreground.
	DecisionThreshold float64
	// LearningRate is the histogram aging rate in (0,1]: each frame the
	// histogram is scaled by (1-LearningRate) and the observed bin is boosted.
	LearningRate float64
	// OpenKernel, when greater than 1, morphologically opens the mask at that
	// odd size before Apply returns it (see [CleanupMask]).
	OpenKernel int
	// contains filtered or unexported fields
}

type BackgroundSubtractorGSOC struct {
	// ShadowParams supplies the embedded DetectShadows / ShadowValue /
	// ShadowThreshold configuration and their setters.
	ShadowParams

	// NSamples is the number of intensity samples stored per pixel.
	NSamples int
	// MinMatches is the minimum number of neighbouring samples for a background
	// classification.
	MinMatches int
	// DistThreshold is the absolute intensity distance within which a stored
	// sample counts as a match.
	DistThreshold float64
