	left, right := makePair(64, 24, 8)
	l := cudastereo.NewGpuMatFromMat(left)
	r := cudastereo.NewGpuMatFromMat(right)

	bm := cudastereo.CreateStereoBM(16, 7)
	disp := bm.Compute(l, r, nil).Download()

	fmt.Println(disp.Data[12*disp.Cols+50])
