	h := imghash.NewDHash()
	hb := imghash.Difference(base)
	dBlur := h.Compare(hb, imghash.Difference(blurred))
	dChecker := h.Compare(hb, imghash.Difference(checker))
	fmt.Println(dBlur < dChecker)
