types.signature:
type BinaryDescriptor struct {
	// NumBands is the number of parallel bands the support region is split into
	// across the width of the line. It must be positive.
	NumBands int
	// BandWidth is the thickness, in pixels, of each band measured
	// perpendicular to the line. The total support-region width is
	// NumBands × BandWidth.
	BandWidth int
}

type BinaryDescriptorParams struct {
	// NumOfOctaves is the number of scale-pyramid octaves the descriptor is
	// meant to operate over (used by the multi-octave pipeline). It must be at
	// least 1.
	NumOfOctaves int
	// WidthOfBand is the thickness in pixels of each parallel band of the
	// support region, corresponding to upstream widthOfBand_. It maps to
	// [BinaryDescriptor.BandWidth].
	WidthOfBand int
	// NumOfBands is the number of parallel bands across the support region,
	// mapping to [BinaryDescriptor.NumBands].
	NumOfBands int
	// ReductionRatio is the pyramid downsampling factor between consecutive
	// octaves, corresponding to upstream reductionRatio_. It must exceed 1.
	ReductionRatio float64
}

type DMatch struct {
	// QueryIdx is the index of the descriptor in the query set.
	QueryIdx int
	// TrainIdx is the index of the matched descriptor in the train set.
	TrainIdx int
	// Distance is the Hamming distance between the two codes; smaller means
	// more similar.
	Distance int
}

type EDLinesDetector struct {
	// GradThreshold is the minimum gradient magnitude for a pixel to be part of
	// any edge; pixels below it are treated as flat and terminate a trace.
	GradThreshold float64
	// AnchorThreshold is the extra margin, above GradThreshold, by which a pixel
	// must exceed its neighbours along the gradient direction to be chosen as an
	// anchor (a trace seed). Larger values yield fewer, stronger anchors.
	AnchorThreshold float64
	// MinLineLength discards fitted segments shorter than this many pixels.
	MinLineLength float64
	// FitError is the maximum root-mean-square perpendicular distance, in
	// pixels, between an edge chain and the straight line fitted through it; a
	// chain is split into a new segment wherever this tolerance is exceeded.
	FitError float64
}

type GeometricMatchParams struct {
	// MaxDistance is the largest admissible Hamming distance between the two
	// segments' binary codes.
	MaxDistance int
	// MaxAngleDiff is the largest admissible orientation difference in radians,
	// compared modulo π so that opposite directions count as equal. A value <= 0
	// disables the orientation test.
	MaxAngleDiff float64
	// MaxLengthRatio, when greater than 1, requires the longer of the two
	// segments to be at most MaxLengthRatio times the shorter. A value <= 1
	// disables the length test.
	MaxLengthRatio float64
}

type KeyLine struct {
	// StartPoint is the first endpoint of the segment (X is the column, Y the
	// row).
	StartPoint cv.Point
	// EndPoint is the second endpoint of the segment.
	EndPoint cv.Point
	// Angle is the orientation of the segment in radians, computed as
	// math.Atan2(EndPoint.Y-StartPoint.Y, EndPoint.X-StartPoint.X); it lies in
	// the range (-π, π].
	Angle float64
	// Length is the Euclidean distance between the two endpoints in pixels.
	Length float64
	// Response ranks segments; larger is stronger. The detector sets it to the
	// segment length, so sorting by descending Response yields the longest,
	// most prominent segments first.
	Response float64
	// Octave is the scale-pyramid layer the segment was detected in. This port
	// works at a single scale, so it is always 0.
	Octave int
}

type KeyLineEx struct {
	KeyLine

	// ClassID is a caller-assignable label used to group or identify segments;
	// the detector fills it with the segment's index within its octave.
	ClassID int
	// Pt is the midpoint of the segment in original-image coordinates.
	Pt PointF
	// Size is a rough scale measure of the segment, set to its octave-space
	// length so that segments found in coarser octaves report a larger size.
	Size float64
	// StartPointF and EndPointF are the endpoints in original-image coordinates
	// at sub-pixel precision (the rounded integer versions live in the embedded
	// KeyLine).
	StartPointF PointF
	EndPointF   PointF
	// StartPointInOctave and EndPointInOctave are the endpoints expressed in the
	// coordinate system of the octave image the segment was actually detected
	// in, before back-projection to full resolution.
	StartPointInOctave PointF
	EndPointInOctave   PointF
	// LineLength is the Euclidean segment length measured in the octave image
	// (so LineLength × scale ≈ Length).
	LineLength float64
	// NumOfPixels is the number of pixels the segment spans in its octave image,
	// i.e. round(LineLength).
	NumOfPixels int
}

type LSDDetector struct {
	// AngleTol is the level-line orientation tolerance, in radians, used when
	// growing a line-support region: a candidate pixel joins the region only
	// when its level-line angle is within AngleTol of the region's running mean
	// angle. The upstream LSD default is 22.5°.
	AngleTol float64
	// GradThreshold is the minimum gradient magnitude for a pixel to be
	// considered part of any line-support region. Pixels below it are treated
	// as flat. The default derives from AngleTol as 2/sin(AngleTol), matching
	// LSD's gradient-quantisation reasoning.
	GradThreshold float64
	// MinLength discards line-support regions whose fitted segment is shorter
	// than this many pixels.
	MinLength float64
	// MinDensity rejects regions whose aligned-pixel density inside the fitted
	// rectangle (pixels / (length × width)) is below this value; it keeps the
	// detector from accepting blobs as lines. LSD uses 0.7.
	MinDensity float64
	// MinRegionSize discards line-support regions with fewer than this many
	// pixels before any rectangle is fitted.
	MinRegionSize int
}

type LSHIndex struct {
	// contains filtered or unexported fields
}

type PointF struct {
	X float64
	Y float64
}

type ScalePyramid struct {
	// Levels holds one single-channel image per octave, coarsest last.
	Levels []*cv.Mat
	// Scales[o] is the downsampling factor of Levels[o] relative to the
	// original image (Scales[0] == 1).
	Scales []float64
}

