	knn := idx.KnnMatch([][]byte{{0xFF, 0x00, 0xAA, 0x55}}, 1)
	fmt.Println("train index:", knn[0][0].TrainIdx)
	fmt.Println("distance:", knn[0][0].Distance)
}

