}

consts.signature:
const (
	// ModelLinear is a pure 3x3 linear map (3 terms per channel).
	ModelLinear CCMModelType = iota
	// ModelAffine is a 3x3 map plus a constant offset (4 terms).
	ModelAffine
	// ModelPoly2 is the full second-degree polynomial in (r,g,b) including the
	// constant term (10 terms).
	ModelPoly2
	// ModelPoly3 is the full third-degree polynomial in (r,g,b) including the
	// constant term (20 terms).
	ModelPoly3
	// ModelRootPoly2 is the Finlayson root-polynomial of degree 2 (6 terms:
	// r, g, b, √(rg), √(gb), √(rb)); it is invariant to exposure scaling.
	ModelRootPoly2
	// ModelRootPoly3 is the Finlayson root-polynomial of degree 3 (13 terms),
	// also exposure-invariant, with more freedom than [ModelRootPoly2].
	ModelRootPoly3
)

const (
	// CCMLinear3x3 is a pure 3x3 linear map (three coefficients per output
	// channel, no offset). It preserves black and is the classic color matrix.
	CCMLinear3x3 CCMType = iota
	// CCMAffine3x4 is a 3x3 map plus a constant offset per output channel (four
	// coefficients each), able to correct a black-level shift.
	CCMAffine3x4
	// CCMPolynomial expands each color into a fixed degree-2 polynomial
	// (r, g, b, rg, gb, br, r^2, g^2, b^2, 1) before the linear map, capturing
	// mild non-linearity at the cost of more coefficients.
	CCMPolynomial
)

