// stepDetector is a tiny Detector that replays scripted detections.
type stepDetector struct {
	rects [][]cv.Rect
	i     int
}

func (s *stepDetector) DetectMultiScale(_ *cv.Mat) []cv.Rect {
	if s.i >= len(s.rects) {
		return nil
	}
	r := s.rects[s.i]
	s.i++
	return r
}

