type DeepFlowParams struct {
	// Alpha is the smoothness weight of the variational refinement (larger →
	// smoother flow).
	Alpha float64
	// Beta weights the descriptor-matching constraint that anchors the flow to
	// the coarse block-matching correspondences, enabling large displacements.
	Beta float64
	// Scales is the number of pyramid levels (>= 1).
	Scales int
	// Warps is the number of warping (re-linearisation) steps per scale.
	Warps int
	// Iterations is the number of Gauss-Seidel sweeps per warp.
	Iterations int
	// MatchRadius is the integer search radius of the coarse block matcher.
	MatchRadius int
	// PatchRadius is the half-size of the block-matching correlation window.
	PatchRadius int
}

type DualTVL1OpticalFlow struct {
	// Params holds the solver configuration used by Calc.
	Params TVL1Params
}

type ErrorStats struct {
	// Mean is the arithmetic mean error (AEE for endpoint errors).
	Mean float64
	// RMS is the root-mean-square error.
	RMS float64
	// Median is the 50th-percentile error.
	Median float64
	// Max is the largest error.
	Max float64
}

type FlowField struct {
	// Rows is the field height.
	Rows int
	// Cols is the field width.
	Cols int
	// Data holds the interleaved (u, v) displacements, row-major, length
	// Rows*Cols*2.
	Data []float64
}

type PCAFlowParams struct {
	// BasisOrder is the maximum cosine order per axis of the low-dimensional
	// flow subspace (the "PCA prior"). The subspace has (BasisOrder+1)² basis
	// fields per flow component. Order 3–5 captures translation, rotation and
	// smooth divergence/shear.
	BasisOrder int
	// GridStep is the spacing (in pixels) of the sparse seed grid whose
	// Lucas-Kanade matches drive the fit.
	GridStep int
	// Ridge is the Tikhonov regularisation added to the normal equations,
	// stabilising the least-squares fit against noisy or degenerate matches.
	Ridge float64
	// WinRadius is the half-size of the Lucas-Kanade window used to establish
	// each sparse match.
	WinRadius int
}

type PointF struct {
	// X is the horizontal (column) coordinate.
	X float64
	// Y is the vertical (row) coordinate.
	Y float64
}

type RLOFParams struct {
	// WinRadius is the half-size of the tracking window; the window is
	// (2·WinRadius+1)² pixels.
	WinRadius int
	// MaxIters is the maximum number of iteratively-reweighted least-squares
	// updates per point.
	MaxIters int
	// MinEigen is the smallest acceptable eigenvalue of the (normalised)
	// structure tensor; below it a point is declared untrackable.
	MinEigen float64
	// HuberDelta is the residual scale of the Huber M-estimator. Residuals
	// larger than HuberDelta (in intensity units) are down-weighted linearly
	// instead of quadratically, giving robustness to outliers and occlusions.
	HuberDelta float64
	// Illumination enables a per-window additive illumination model (the mean
	// residual is removed each iteration), making the tracker invariant to
	// uniform brightness changes between frames.
	Illumination bool
	// GridStep is the seed spacing (in pixels) used by the dense variant before
	// edge-aware interpolation.
	GridStep int
}

type SimpleFlowParams struct {
	// Scales is the number of pyramid levels (>= 1); each level extends the
	// reachable displacement.
	Scales int
	// SearchRadius is the per-level integer search radius of candidate flows
	// around the inherited estimate.
	SearchRadius int
	// WinRadius is the half-size of the correlation window over which each
	// candidate flow's energy is accumulated.
	WinRadius int
	// SigmaS is the spatial scale of the bilateral weighting inside the
	// correlation window (image-plane distance).
	SigmaS float64
	// SigmaC is the colour/intensity scale of the bilateral weighting (range
	// term), making the energy edge-aware.
	SigmaC float64
}

type TVL1Params struct {
	// Tau is the time step of the dual (TV) ascent update. Stable at 0.25.
	Tau float64
	// Lambda weights the L1 data term against the total-variation regulariser.
	// Smaller Lambda yields smoother flow.
	Lambda float64
	// Theta is the tightness of the quadratic relaxation coupling the flow u to
	// the auxiliary variable v.
	Theta float64
	// Scales is the number of pyramid levels (>= 1). More scales recover larger
	// displacements.
	Scales int
	// Warps is the number of warping (re-linearisation) steps per scale.
	Warps int
	// Iterations is the number of inner primal-dual updates per warp.
	Iterations int
	// Epsilon is the stopping threshold on the mean primal update; a value <= 0
	// disables early stopping and always runs the full Iterations.
	Epsilon float64
}

