type FlynnUnwrapper struct {
	// Weights is the optional per-pixel reliability map (nil means uniform).
	Weights [][]float64
	// MaxIter caps the refinement sweeps (non-positive selects a default).
	MaxIter int
}

type GoldsteinUnwrapper struct {
	// MaxBoxRadius limits how far a residue may pair with an opposite-charge
	// partner before it is cut to the border (non-positive means no limit).
	MaxBoxRadius int
}

type HistogramPhaseUnwrapping struct {
	// contains filtered or unexported fields
}

type HistogramUnwrapper struct {
	// Params configures the underlying histogram unwrapper; the zero value is
	// normalised to sensible defaults.
	Params Params
}

type Params struct {
	// Width is the expected number of columns of the wrapped phase map.
	Width int
	// Height is the expected number of rows of the wrapped phase map.
	Height int
	// HistogramThresh is the reliability value that separates the fine "small"
	// bins (used for reliable, low-value edges) from the coarse "large" bins
	// (used for the long tail of unreliable edges). It is expressed in the same
	// units as the inverse-reliability measure (a sum of squared second
	// differences). The OpenCV default is 3*pi*pi.
	HistogramThresh float64
	// NrOfSmallBins is the number of fine histogram bins covering
	// [0, HistogramThresh). Must be >= 1.
	NrOfSmallBins int
	// NrOfLargeBins is the number of coarse histogram bins covering
	// [HistogramThresh, maxReliability]. Must be >= 1.
	NrOfLargeBins int
}

type QualityGuidedUnwrapper struct {
	// Quality is the optional higher-is-better reliability map (nil selects the
	// negated phase-derivative variance).
	Quality [][]float64
}

type Residue struct {
	Row, Col, Charge int
}

type Unwrapper interface {
	Unwrap(wrapped [][]float64) ([][]float64, error)
}

type WeightedLeastSquaresUnwrapper struct {
	// Weights is the optional per-pixel reliability map (nil means uniform).
