consts.signature:
const (
	// RecursFilter requests OpenCV's recursive-filter variant. Here it maps to a
	// bilateral filter.
	RecursFilter EdgePreservingFlag = 1
	// NormconvFilter requests OpenCV's normalized-convolution variant. Here it
	// also maps to a bilateral filter.
	NormconvFilter EdgePreservingFlag = 2
)

const (
	// InpaintTelea fills the masked region with a simplified fast-marching
	// scheme (after Telea, 2004): unknown pixels are processed in order of
	// increasing distance from the mask boundary, each set to a distance-weighted
	// average of its already-known neighbours. It reconstructs smooth gradients
	// from the boundary inward.
	InpaintTelea InpaintMethod = iota
	// InpaintNS fills the masked region by solving the Laplace equation over it
	// (a diffusion / harmonic fill) with the surrounding pixels as boundary
	// conditions, via in-place Gauss–Seidel iteration. The result is the
	// smoothest interpolation that agrees with the border.
	InpaintNS
)

const (
	// NormalClone imports the source's gradients directly, so the cloned region
	// takes on the source's texture while its overall colour is retargeted to the
	// destination at the seam.
	NormalClone SeamlessCloneMode = iota
	// MixedClone uses, per neighbour, whichever of the source and destination
	// gradients is larger in magnitude. This preserves salient destination
	// structure under the pasted region (useful when the source has flat areas).
	MixedClone
)

