// quad builds a small four-quadrant colour image for the examples.
func quad() *cv.Mat {
	img := cv.NewMat(20, 20, 3)
	colors := [4][3]uint8{{220, 20, 20}, {20, 220, 20}, {20, 20, 220}, {220, 220, 20}}
	for y := 0; y < 20; y++ {
		for x := 0; x < 20; x++ {
			q := 0
			if x >= 10 {
				q |= 1
			}
			if y >= 10 {
				q |= 2
			}
			img.SetPixel(y, x, colors[q][:])
		}
	}
	return img
}

