const (
	// HausdorffL1 uses the Manhattan (city-block) distance |dx| + |dy|.
	HausdorffL1 = 1
	// HausdorffL2 uses the Euclidean distance √(dx² + dy²).
	HausdorffL2 = 2
)

const (
	// ContoursMatchI1 sums |1/m_i^A − 1/m_i^B| over the Hu moments.
	ContoursMatchI1 = 1
	// ContoursMatchI2 sums |m_i^A − m_i^B| over the Hu moments.
	ContoursMatchI2 = 2
	// ContoursMatchI3 takes the maximum of |m_i^A − m_i^B| / |m_i^A|.
	ContoursMatchI3 = 3
)

const (
	// DistL1 uses ρ(r) = |r| (least absolute deviation): weight 1/|r|.
	DistL1 = 1
	// DistL2 uses ρ(r) = r²/2 (ordinary total least squares): every weight 1.
	DistL2 = 2
	// DistL12 uses the L1–L2 (fair-like) loss 2(√(1+r²/2) − 1).
	DistL12 = 4
	// DistFair uses Fair's loss with tuning constant 1.3998.
	DistFair = 5
	// DistWelsch uses Welsch's redescending loss with tuning constant 2.9846.
	DistWelsch = 6
	// DistHuber uses Huber's loss with tuning constant 1.345.
	DistHuber = 7
)

