examples.code:
img := cv.NewMat(64, 48, 1)
pyr := BuildOpticalFlowPyramid(img, 3)
for i, lv := range pyr {
	fmt.Printf("level %d: %dx%d\n", i, lv.Rows, lv.Cols)
}

prob := cv.NewFloatMat(60, 60)
for y := 0; y < 60; y++ {
	for x := 0; x < 60; x++ {
		dx := float64(x-40) / 5
		dy := float64(y-20) / 5
		prob.Data[y*60+x] = math.Exp(-0.5 * (dx*dx + dy*dy))
	}
}
_, w := MeanShift(prob, cv.Rect{X: 5, Y: 5, Width: 16, Height: 16}, NewTermCriteria(50, 0.05))
cx := w.X + w.Width/2
cy := w.Y + w.Height/2
fmt.Printf("near mode (40,20): %v\n", math.Abs(float64(cx-40)) <= 1 && math.Abs(float64(cy-20)) <= 1)

prev := cv.NewMat(24, 24, 1)
next := cv.NewMat(24, 24, 1)
for y := 0; y < 24; y++ {
	for x := 0; x < 24; x++ {
		prev.Set(y, x, 0, uint8((x*37)%251))
		nx := x - 1
		if nx < 0 {
			nx = 0
		}
		next.Set(y, x, 0, uint8((nx*37)%251))
	}
}
flow := CalcOpticalFlowFarneback(prev, next, 2, 2)
dx, dy := flow.MeanFlow(4)
fmt.Printf("mean flow = (%.1f, %.1f)\n", dx, dy)

kf := NewKalmanFilter(2, 1)
kf.TransitionMatrix = [][]float64{{1, 1}, {0, 1}}
kf.MeasurementMatrix = [][]float64{{1, 0}}
kf.ProcessNoiseCov = [][]float64{{1e-4, 0}, {0, 1e-4}}
kf.MeasurementNoiseCov = [][]float64{{0.1}}

for k := 1; k <= 20; k++ {
	kf.Predict()
	kf.Correct([]float64{2 * float64(k)})
}
fmt.Printf("pos=%.1f vel=%.1f\n", kf.StatePost[0], kf.StatePost[1])

from := []PointF{{0, 0}, {10, 0}, {0, 10}, {10, 10}}

to := []PointF{{5, 1}, {5, 21}, {-15, 1}, {-15, 21}}
tf, ok := EstimateAffinePartial2D(from, to)
fmt.Printf("ok=%v scale=%.1f angleDeg=%.0f t=(%.0f,%.0f)\n",
	ok, tf.Scale, tf.Angle*180/math.Pi, tf.Tx, tf.Ty)

