// makeExampleDir returns a fresh temporary directory for example output.
func makeExampleDir() (string, error) {
	return os.MkdirTemp("", "videoio-example-")
}

func main() {
	dir, err := makeExampleDir()
	if err != nil {
		log.Fatal(err)
