func main() {
	var kp1, kp2 []xfeatures2d.KeyPoint
	var matches []xfeatures2d.DMatch
	// A consistent block of matches translated by (20, 20).
	for gy := 0; gy < 10; gy++ {
		for gx := 0; gx < 10; gx++ {
			x, y := 40+gx*4, 40+gy*4
			i := len(kp1)
			kp1 = append(kp1, xfeatures2d.KeyPoint{Pt: cv.Point{X: x, Y: y}})
