type ACFFeatureEvaluator struct {
	// contains filtered or unexported fields
}

type Feature struct {
	// Channel selects the feature channel, in [0, NumChannels).
	Channel int
	// X, Y are the rectangle's top-left corner within the detection window.
	X, Y int
	// W, H are the rectangle's width and height in pixels.
	W, H int
}

type FeaturePool struct {
	// WinW, WinH are the detection-window dimensions the features address.
	WinW, WinH int
	// Features is the ordered list of probes; a feature vector produced by the
	// pool has one entry per element, in this order.
	Features []Feature
}

type Stump struct {
	// Feature is the index into the feature vector this stump reads.
	Feature int
	// Threshold is the decision boundary on that feature value.
	Threshold float64
	// Polarity is +1 or -1. When +1 a value >= Threshold votes for the positive
	// class; when -1 the sense is reversed.
	Polarity int
	// Alpha is the stump's boosting weight (its vote magnitude).
	Alpha float64
}

type WBDetector struct {
	// WinW, WinH are the detection-window dimensions in pixels. Training patches
	// are resized to this size.
	WinW, WinH int
	// Rounds is the maximum number of boosting stumps to fit.
	Rounds int
	// NumFeatures is the size of the random integral-channel feature pool.
	NumFeatures int
	// Seed makes feature-pool sampling and training reproducible.
	Seed int64
	// ScaleFactor is the ratio between successive pyramid levels (> 1). Values
	// <= 1 default to 1.2.
	ScaleFactor float64
	// Step is the sliding-window stride in pixels (>= 1).
	Step int
	// NMSOverlap is the intersection-over-union above which overlapping
	// detections are merged by non-maximum suppression, in [0,1].
	NMSOverlap float64
	// DetectThreshold is the minimum confidence score a window must reach to be
	// reported. The natural boundary is 0.
	DetectThreshold float64
	// contains filtered or unexported fields
}

type WaldBoost struct {
	// Rounds is the maximum number of stumps to fit.
	Rounds int
	// DetectionRate is the fraction of positive training samples the SPRT
	// thresholds must retain at every stage, in (0,1]. Values outside that range
	// default to 0.995. Lower values prune more aggressively.
	DetectionRate float64

	// Stumps is the fitted ensemble, in evaluation order.
	Stumps []Stump
	// SPRT holds one rejection threshold per stump: after evaluating stump i the
	// running score must be >= SPRT[i] or the sample is rejected.
	SPRT []float64
	// Trained reports whether Train has completed successfully.
	Trained bool
}

