		pos = append(pos, target(rng))
		p := cv.NewMat(24, 24, 1)
		for j := range p.Data {
			p.Data[j] = uint8(90 + rng.Intn(80))
		}
		neg = append(neg, p)
	}

	d := xobjdetect.NewWBDetector()
	d.Rounds = 30
	d.NumFeatures = 150
	if err := d.Train(pos, neg); err != nil {
		panic(err)
	}

