type DarkChannelDehazer struct {
	// PatchRadius is the half-size of the local window used for the dark
	// channel and the raw transmission estimate. Values <= 0 default to 3.
	PatchRadius int
	// Omega in (0,1] is the fraction of haze kept, which leaves a little haze
	// for distant objects so the result still looks natural. Values outside
	// (0,1] default to 0.95.
	Omega float64
	// T0 is the lower bound on transmission, preventing division by near-zero in
	// dense haze. Values <= 0 default to 0.1.
	T0 float64
	// GuidedRadius is the window half-size of the guided-filter refinement of
	// the transmission map. Values <= 0 default to 4*PatchRadius.
	GuidedRadius int
	// GuidedEps is the guided-filter regularisation (in normalised [0,1]^2
	// units); larger values smooth more. Values <= 0 default to 1e-3.
	GuidedEps float64
}

consts.signature:
const (
	// FSRBest favours reconstruction quality: it uses a larger support border
	// and more model-building iterations per block. This is OpenCV's
	// INPAINT_FSR_BEST.
	FSRBest FSRMode = iota
	// FSRFast favours speed with a smaller border and fewer iterations,
	// mirroring OpenCV's INPAINT_FSR_FAST.
	FSRFast
)

types.signature:
type GrayworldWB struct {
	// SaturationThreshold is in (0,1]. A pixel is excluded from the mean
	// computation when its per-pixel saturation (max-min)/max exceeds this
	// value. A value of 1 includes every pixel.
	SaturationThreshold float64
}

type LearningBasedWB struct {
	// RangeMaxVal is the maximum sample value (255 for 8-bit data). Samples at
	// or above SaturationThreshold*RangeMaxVal are treated as clipped and
	// excluded from the estimate.
	RangeMaxVal float64
	// SaturationThreshold is in (0,1]; pixels whose maximum channel exceeds
	// this fraction of RangeMaxVal are ignored.
	SaturationThreshold float64
	// HistBinNum controls the quantisation of the internal chromaticity
	// accumulation. It is retained for parity with OpenCV's API and to bound
	// the feature resolution; values <= 0 default to 64.
	HistBinNum int
}

consts.signature:
const (
	// OilIntensityLuma buckets by BT.601 luma (0.299R+0.587G+0.114B). This is
	// the behaviour of the plain [Oilpainting] entry point.
	OilIntensityLuma OilIntensity = iota
	// OilIntensityValue buckets by the HSV "value", i.e. the maximum channel.
	OilIntensityValue
	// OilIntensityAverage buckets by the unweighted channel average.
	OilIntensityAverage
)

types.signature:
type SimpleWB struct {
	// InputMin and InputMax bound the samples considered when building each
	// channel histogram. Samples outside the range are ignored.
	InputMin, InputMax float64
	// OutputMin and OutputMax are the target range the stretched channel is
	// mapped into.
	OutputMin, OutputMax float64
	// P is the percentage (0..50) of the lowest and highest samples clipped
	// from each channel before computing its stretch bounds.
	P float64
}

type TonemapDurand struct {
	// Gamma is the gamma applied to the final result (1.0 = none). Values <= 0
	// default to 1.
	Gamma float64
	// Contrast is the target contrast (in log10 units) the base layer is
	// compressed to; smaller values flatten the image more. Values <= 0 default
	// to 4.
	Contrast float64
	// Saturation scales colour saturation of the result; 1 keeps it, <1
	// desaturates, >1 boosts. Values < 0 default to 1.
	Saturation float64
	// SigmaSpace is the spatial standard deviation (in pixels) of the bilateral
	// filter. Values <= 0 default to 2.
	SigmaSpace float64
	// SigmaColor is the range (log-luminance) standard deviation of the
	// bilateral filter. Values <= 0 default to 2.
	SigmaColor float64
}

type WhiteBalancer interface {
	// BalanceWhite returns a white-balanced copy of src. Implementations
	// require a three-channel RGB image and panic otherwise.
	BalanceWhite(src *cv.Mat) *cv.Mat
}

